<?php

declare(strict_types=1);

/**
 * Applies the 2026-06-22 ArtsFolio admin attention, watermark, navigation,
 * table filtering, and operations-console update.
 *
 * Run from the ArtsFolio project root:
 *   php /path/to/apply_artsfolio_admin_attention_watermark_filters_20260622.php
 */

$root = getcwd();
if (!is_string($root) || !is_file($root . '/composer.json') || !is_dir($root . '/app/Http')) {
    fwrite(STDERR, "Run this script from the ArtsFolio project root.\n");
    exit(1);
}

$backupRoot = $root . '/storage/update-backups/admin-attention-watermark-' . gmdate('YmdHis');
if (!is_dir($backupRoot) && !mkdir($backupRoot, 0775, true) && !is_dir($backupRoot)) {
    throw new RuntimeException('Could not create update backup directory.');
}

$files = [
    'PROJECT_STATE.md' => '',
    'app/Http/Controllers/Platform/Admin/OperationsController.php' => '',
    'app/Http/Controllers/Platform/DirectoryController.php' => '',
    'app/Http/Controllers/Platform/HelpController.php' => '',
    'app/Http/Controllers/Platform/HomeController.php' => '',
    'app/Http/Controllers/Platform/MarketingController.php' => '',
    'app/Http/Controllers/Platform/PricingController.php' => '',
    'app/Http/Controllers/Platform/SignupController.php' => '',
    'app/Http/Controllers/Tenant/Admin/ArtworksController.php' => '',
    'app/Http/Controllers/Tenant/Admin/EmailSignupsController.php' => '',
    'app/Http/Controllers/Tenant/Admin/SettingsController.php' => '',
    'app/Http/Controllers/Tenant/MediaController.php' => '',
    'app/Http/View/AdminLayout.php' => '',
    'app/Http/View/AuthPage.php' => '',
    'app/Http/View/PlatformChrome.php' => '',
    'app/Http/View/TenantAdminLayout.php' => '',
    'app/Http/View/TenantAdminNav.php' => '',
    'app/Platform/Monitoring/OperationsMonitorRepository.php' => '',
    'app/Tenant/Media/WatermarkService.php' => '',
    'docs/admin/admin-notifications-watermarks-and-table-tools.md' => '',
    'docs/dev/admin-ui-and-watermark-runtime.md' => '',
    'docs/user/image-watermarks.md' => '',
    'fix.txt' => '',
    'public/assets/admin-shell-refactor.css' => '',
    'public/assets/admin-table-tools.js' => '',
    'public/assets/auth.css' => '',
    'scripts/test/admin_attention_watermark_operations_static.php' => '',
    'scripts/test/preflight.sh' => '',
];

foreach ($files as $relativePath => $encoded) {
    $target = $root . "/" . $relativePath;
    $directory = dirname($target);
    if (!is_dir($directory) && !mkdir($directory, 0775, true) && !is_dir($directory)) {
        throw new RuntimeException("Could not create directory: {$directory}");
    }
    if (is_file($target)) {
        $backup = $backupRoot . "/" . $relativePath;
        $backupDirectory = dirname($backup);
        if (!is_dir($backupDirectory) && !mkdir($backupDirectory, 0775, true) && !is_dir($backupDirectory)) {
            throw new RuntimeException("Could not create backup directory: {$backupDirectory}");
        }
        if (!copy($target, $backup)) {
            throw new RuntimeException("Could not back up: {$relativePath}");
        }
    }
    $contents = base64_decode($encoded, true);
    if (!is_string($contents)) {
        throw new RuntimeException("Embedded file payload is invalid: {$relativePath}");
    }
    $temporary = $target . ".artsfolio-update-tmp";
    if (file_put_contents($temporary, $contents, LOCK_EX) === false || !rename($temporary, $target)) {
        @unlink($temporary);
        throw new RuntimeException("Could not install: {$relativePath}");
    }
    echo "Installed {$relativePath}\n";
}

echo "\nUpdate installed. Backup: {$backupRoot}\n";
echo "Run: ./scripts/test/preflight.sh\n";

// End of file.
